/* 
Confession time:
I _may_ have gotten some help from copilot on this one. I'm not great at JSON... 

Haven't decided whether I'm proud or ashamed of this yet.
*/

SELECT
    msg.[offset],
    msg.sequenceNumber,
    body_inner.logicalid,
    body_inner.operation,
    body_inner.time,
    body_inner.datatext
FROM
    OPENJSON(@jsonmessages)
    WITH (
        body NVARCHAR(MAX) '$.body',
        [offset] NVARCHAR(50) '$.offset',
        sequenceNumber INT '$.sequenceNumber'
    ) AS msg
CROSS APPLY
    OPENJSON(TRY_CAST(msg.body AS JSON))
    WITH (
        logicalid NVARCHAR(400) '$.logicalid',
        operation NVARCHAR(400) '$.operation',
        time DATETIMEOFFSET '$.time',
        datatext NVARCHAR(400) '$.data'
    ) AS body_inner
ORDER BY body_inner.logicalid;